Uint8List mustDecodeHex(String label, String hex) {
  final cleaned = hex.replaceAll(" ", "");
  if (cleaned.isEmpty || cleaned.contains("REPLACE_WITH")) {
    throw StateError(
      "$label is still a placeholder. Replace it before running.",
    );
  }
  return Uint8List.fromList(HEX.decode(cleaned));
}

Future<void> main() async {
  final socket = await RawDatagramSocket.bind("127.0.0.1", 4433);

  QuicServerSession? quicSession;

  print("server listening ip:${socket.address.address}:${socket.port}");

  socket.listen((ev) {
    if (ev == RawSocketEvent.read) {
      final dg = socket.receive();
      if (dg != null) {
        print("Data datagram received: ${dg.data.length}");

        quicSession ??= QuicServerSession(
          socket: socket,
          peerAddress: dg.address,
          peerPort: dg.port,
          flight: ServerHandshakeFlight(
            serverHello: mustDecodeHex("serverHelloHex", serverHelloHex),
            encryptedExtensions: mustDecodeHex(
              "encryptedExtensionsHex",
              encryptedExtensionsHex,
            ),
            certificate: mustDecodeHex("certificateHex", certificateHex),
            certificateVerify: mustDecodeHex(
              "certificateVerifyHex",
              certificateVerifyHex,
            ),
          ),
        );

        final packetList = splitCoalescedPackets(dg.data);
        print(packetList.length);

        for (final pkt in packetList) {
          quicSession!.handleDatagram(pkt);
        }
      }
    }
  });
}
